"use strict";const t=require("../common/vendor.js"),o=require("../store/index.js"),e=require("./api.js"),n=require("./accountBook.js"),r=require("./auth.js");exports.goToAddTransaction=async function(c=0){if(!r.requireWechatLogin())return;let i=null,s=0;if("shared"===(t.index.getStorageSync("accountBookTab")||"personal")){const r=await async function(){const t=o.store.state.currentSharedAccountBook;if(t&&1!==t.status)return t;try{const t=await e.api.sharedAccountBooks.getList(),r=n.pickLatestActiveSharedBook(t);if(r){const t=function(t){return{...t,type:1}}(r);return o.store.commit("SET_CURRENT_SHARED_ACCOUNT_BOOK",t),t}}catch(r){console.error("加载集体账本失败",r)}return null}();if(!r)return void t.index.showToast({title:"还没有进行中的集体账本",icon:"none"});i=r.id,s=1}else{const e=o.store.state.currentAccountBook;if(!e)return void t.index.showToast({title:"请先选择账本",icon:"none"});i=e.id,s=e.type||0}t.index.navigateTo({url:`/pages/add-transaction/add-transaction?type=${c}&accountBookId=${i}&accountBookType=${s}`})};
